tests:
def test_parse_object():
    result = JSONParser('{"name": "Alice", "age": 30}').parse()
    assert result == {'name': 'Alice', 'age': 30}

def test_parse_array():
    result = JSONParser('[1, 2, 3]').parse()
    assert result == [1, 2, 3]

def test_parse_nested():
    result = JSONParser('{"data": [1, {"x": true}]}').parse()
    assert result == {'data': [1, {'x': True}]}

def test_parse_string():
    result = JSONParser('"hello world"').parse()
    assert result == 'hello world'

def test_parse_empty_structures():
    assert JSONParser('{}').parse() == {}
    assert JSONParser('[]').parse() == []

def test_parse_escaped_strings():
    result = JSONParser('{"msg": "hello\\nworld"}').parse()
    assert result == {'msg': 'hello\nworld'}
